INSERT INTO collections (id, collection_name, data, created_at, updated_at) VALUES ('p-001', 'products', '{"id":"p-001","slug":"maximus-sirius-led-h4-85w","name":"Maximus Sirius LED Ultra Bright Headlights H4 - 85W","sku":"MXS-LED-H4-85W","brand":"Maximus","brandSlug":"maximus","category":"LED & Lighting","categorySlug":"led-lighting","images":[{"id":"i1","url":"https://images.unsplash.com/photo-1558981806-ec527fa84c39?auto=format&fit=crop&w=600&h=600&q=80","alt":"LED H4 Headlight","isPrimary":true},{"id":"i2","url":"https://images.unsplash.com/photo-1558981806-ec527fa84c39?auto=format&fit=crop&w=600&h=600&q=80","alt":"LED Headlight side view","isPrimary":false},{"id":"i3","url":"https://images.unsplash.com/photo-1519681393784-d120267933ba?auto=format&fit=crop&w=600&h=600&q=80","alt":"LED installed on car","isPrimary":false}],"price":15000,"originalPrice":18000,"discount":17,"stock":45,"inStock":true,"rating":5,"reviewCount":1,"description":"Maximus Sirius series ultra-bright LED headlights deliver 8500 lumens per pair. Compatible with projector and reflector housings. CANBUS compatible with anti-flicker design. Easy plug-and-play installation for most vehicles.","shortDescription":"85W ultra-bright LED headlight pair, H4 base, 8500 lumens, CANBUS compatible","specifications":[{"id":"359e9783-7920-4446-b423-e77c1fb980c5","label":"Wattage","value":"85W"},{"id":"efc03c7d-a842-47ce-a7bd-fd2606e80fd4","label":"Lumens","value":"8500 lm/pair"},{"id":"713f61de-418a-4c6c-b361-04639817eb7e","label":"Color Temp","value":"6500K White"},{"id":"d56ba760-7c4d-4f9f-bb71-5d2108143172","label":"Base","value":"H4"},{"id":"03dc4c6f-c963-4744-9b0a-f529c13dced0","label":"Cooling","value":"Turbo Fan + Heatsink"},{"id":"6547f535-7bd1-4506-978d-3d0cead906cf","label":"Warranty","value":"1 Year"},{"id":"ba163077-f219-4f94-b585-ed3d72978b41","label":"CANBUS","value":"Compatible"},{"id":"e1f5adc7-1d9f-4daa-9f48-e483c8ab19c9","label":"IP Rating","value":"IP67 Waterproof"}],"vehicleCompatibility