INSERT INTO collections (id, collection_name, data, created_at, updated_at) VALUES ('svc-2', 'services', '{"id":"svc-2","slug":"ceramic-coating","type":"ceramic","name":"Ceramic Coating","description":"Nano-ceramic coating that permanently bonds with your paint for superior gloss, hydrophobic protection, and UV resistance. Applied by certified technicians.","image":"https://images.unsplash.com/photo-1607860108855-64acf2078ed9?auto=format&fit=crop&w=600&h=400&q=80","priceFrom":18000,"priceTo":75000,"duration":"2-3 Days","features":["9H Hardness","Hydrophobic Effect","UV Protection","3-5 Year Life","Mirror Gloss Finish"],"popular":true}', NOW(), NOW());
INSERT INTO collections (id, collection_name, data, created_at, updated_at) VALUES ('svc-3', 'services', '{"id":"svc-3","slug":"car-detailing","type":"detailing","name":"Car Detailing","description":"Complete interior and exterior detailing. Paint correction, deep clean, clay bar treatment, wax, and full protection for a showroom-fresh finish.","image":"https://images.unsplash.com/photo-1596838132731-3301c3fd4317?auto=format&fit=crop&w=600&h=400&q=80","priceFrom":5000,"priceTo":35000,"duration":"4-8 Hours","features":["Paint Correction","Deep Interior Clean","Engine Bay Wash","Odor Removal","Machine Polishing"],"popular":false}', NOW(), NOW());
