INSERT INTO services (id, slug, type, name, price_from, data) VALUES ('svc-2', 'ceramic-coating', 'ceramic', 'Ceramic Coating', 18000, '{"id":"svc-2","slug":"ceramic-coating","type":"ceramic","name":"Ceramic Coating","description":"Nano-ceramic coating that permanently bonds with your paint for superior gloss, hydrophobic protection, and UV resistance. Applied by certified technicians.","image":"https://images.unsplash.com/photo-1607860108855-64acf2078ed9?auto=format&fit=crop&w=600&h=400&q=80","priceFrom":18000,"priceTo":75000,"duration":"2-3 Days","features":["9H Hardness","Hydrophobic Effect","UV Protection","3-5 Year Life","Mirror Gloss Finish"],"popular":true}');
