INSERT INTO hero_slides (id, tag, title, mobile_title, highlight, mobile_cta, description, cta_label, cta_href, secondary_label, secondary_href, product_image, product_label, product_price, badge_icon, badge_text, stat1_value, stat1_label, stat2_value, stat2_label, stat3_value, stat3_label, left_bg, right_bg, accent, accent_light, sort_order, is_active, data) VALUES ('hero-slide-1', '★ Best Seller', 'Custom Made\nSeat Covers', 'Custom Seat Covers', 'Premium PU/PVC', 'Shop Now', 'Top premium quality leather PU & PVC fabric seat covers. Custom fit for 200+ models with diamond stitching and expert fitting at our Lahore studio.', 'Shop Seat Covers', '/products?category=custom-seat-covers', 'Get Free Quote', '/contact', 'https://images.unsplash.com/photo-1760161339261-56487b766a17?auto=format&fit=crop&w=600&h=600&q=85', 'Custom PU/PVC Leather', 'From Rs. 12,000', 'Star', 'Most Popular', '200+', 'Car Models', 'All', 'Colours', '1 Yr', 'Warranty', 'from-[#0d0d0d] via-[#1a0a00] to-[#0d0d0d]', 'from-[#f5f0eb] to-[#ede8e0]', '#D50000', '#ff5252', 0, 1, '{"id":"hero-slide-1","tag":"★ Best Seller","title":"Custom Made\\nSeat Covers","mobileTitle":"Custom Seat Covers","highlight":"Premium PU/PVC","mobileCta":"Shop Now","description":"Top premium quality leather PU & PVC fabric seat covers. Custom fit for 200+ models with diamond stitching and expert fitting at our Lahore studio.","ctaLabel":"Shop Seat Covers","ctaHref":"/products?category=custom-seat-covers","secondaryLabel":"Get Free Quote","secondaryHref":"/contact","productImage":"https://images.unsplash.com/photo-1760161339261-56487b766a17?auto=format&fit=crop&w=600&h=600&q=85","productLabel":"Custom PU/PVC Leather","productPrice":"From Rs. 12,000","badgeIcon":"Star","badgeText":"Most Popular","stat1Value":"200+","stat1Label":"Car Models","stat2Value":"All","stat2Label":"Colours","stat3Value":"1 Yr","stat3Label":"Warranty","leftBg":"from-[#0d0d0d] via-[#1a0a00] to-[#0d0d0d]","rightBg":"from-[#f5f0eb] to-[#ede8e0]","accent":"#D50000","accentLight":"#ff5252","sortOrder":0,"isActive":true}');
INSERT INTO hero_slides (id, tag, title, mobile_title, highlight, mobile_cta, description, cta_label, cta_href, secondary_label, secondary_href, product_image, product_label, product_price, badge_icon, badge_text, stat1_value, stat1_label, stat2_value, stat2_label, stat3_value, stat3_label, left_bg, right_bg, accent, accent_light, sort_order, is_active, data) VALUES ('hero-slide-2', '🛡️ All Weather', 'Car Top\nCover', 'Car Top Cover', 'Sun · Dust · Rain', 'Shop Covers', 'Heavy-duty waterproof car top covers with UV-resistant coating. Universal and premium fitted options to protect your vehicle outdoors.', 'Shop Top Covers', '/products?category=car-top-cover', 'View Collection', '/products?category=car-top-cover', 'https://images.unsplash.com/photo-1542317048-7a6ce1a438c8?auto=format&fit=crop&w=600&h=600&q=85', 'Waterproof Top Cover', 'From Rs. 6,500', 'Umbrella', 'UV Protected', '100%', 'Waterproof', 'UV', 'Resistant', '6 Mo', 'Warranty', 'from-[#0d0d18] via-[#060618] to-[#0d0d18]', 'from-[#e8eaf6] to-[#dde0f5]', '#2563EB', '#93C5FD', 1, 1, '{"id":"hero-slide-2","tag":"🛡️ All Weather","title":"Car Top\\nCover","mobileTitle":"Car Top Cover","highlight":"Sun · Dust · Rain","mobileCta":"Shop Covers","description":"Heavy-duty waterproof car top covers with UV-resistant coating. Universal and premium fitted options to protect your vehicle outdoors.","ctaLabel":"Shop Top Covers","ctaHref":"/products?category=car-top-cover","secondaryLabel":"View Collection","secondaryHref":"/products?category=car-top-cover","productImage":"https://images.unsplash.com/photo-1542317048-7a6ce1a438c8?auto=format&fit=crop&w=600&h=600&q=85","productLabel":"Waterproof Top Cover","productPrice":"From Rs. 6,500","badgeIcon":"Umbrella","badgeText":"UV Protected","stat1Value":"100%","stat1Label":"Waterproof","stat2Value":"UV","stat2Label":"Resistant","stat3Value":"6 Mo","stat3Label":"Warranty","leftBg":"from-[#0d0d18] via-[#060618] to-[#0d0d18]","rightBg":"from-[#e8eaf6] to-[#dde0f5]","accent":"#2563EB","accentLight":"#93C5FD","sortOrder":1,"isActive":true}');
